import { GoogleGenAI, Type, Modality } from "@google/genai";
import { Story, ImageSize, Language } from "./types";

// Helper to decode base64 to bytes
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Helper to decode PCM data
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export class GeminiService {
  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateStoryStructure(prompt: string, language: Language, pageCount: number = 5): Promise<Story> {
    const ai = this.getAI();
    const langName = language === 'en' ? 'English' : 'Lithuanian';
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create an enchanting, detailed children's story based on: "${prompt}". 
      THE STORY MUST BE WRITTEN IN ${langName.toUpperCase()}.
      Return the story as a JSON object with a title and exactly ${pageCount} pages. 
      Each page must have "text" (a rich, engaging paragraph of 4-6 sentences) and "imagePrompt" (a highly detailed English description for a whimsical, cinematic children's book illustration).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            pages: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  imagePrompt: { type: Type.STRING }
                },
                required: ["text", "imagePrompt"]
              }
            }
          },
          required: ["title", "pages"]
        }
      }
    });

    const parsed = JSON.parse(response.text || '{}');
    return { ...parsed, language } as Story;
  }

  async generateImage(prompt: string, size: ImageSize): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: `A magical children's book illustration: ${prompt}. Soft cinematic lighting, vibrant colors, dreamy whimsical style, professional art quality.` }]
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: size
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Failed to generate image");
  }

  async generateSpeech(text: string, language: Language): Promise<string> {
    const ai = this.getAI();
    const langName = language === 'en' ? 'English' : 'Lithuanian';
    const voice = language === 'en' ? 'Zephyr' : 'Kore';

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Read this story page slowly and expressively in ${langName}: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voice } 
          }
        }
      }
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Failed to generate speech");
    return base64Audio;
  }
}

export const gemini = new GeminiService();

import React, { useState, useEffect, useRef } from 'react';
import { Story, Language } from '../types';
import { translations } from '../translations';
import { decodeBase64, decodeAudioData } from '../geminiService';

interface Props {
  story: Story;
  currentIndex: number;
  onPageChange: (index: number) => void;
  onReset?: () => void;
  language: Language;
}

const StoryReader: React.FC<Props> = ({ story, currentIndex, onPageChange, onReset, language }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [highlightIndex, setHighlightIndex] = useState(-1);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const startTimeRef = useRef<number>(0);
  const animationFrameRef = useRef<number | null>(null);

  const t = translations[language];
  const totalPages = story.pages.length;
  const isLastPage = currentIndex === totalPages - 1;
  const currentPage = story.pages[currentIndex];

  // Split text into words for highlighting
  const words = currentPage?.text ? currentPage.text.split(/\s+/) : [];

  const handleNext = () => {
    if (currentIndex < totalPages - 1) onPageChange(currentIndex + 1);
  };

  const handlePrev = () => {
    if (currentIndex > 0) onPageChange(currentIndex - 1);
  };

  // Touch handling for swipe
  const touchStartX = useRef<number | null>(null);
  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
  };
  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStartX.current) return;
    const diff = touchStartX.current - e.changedTouches[0].clientX;
    if (diff > 60) handleNext();
    else if (diff < -60) handlePrev();
    touchStartX.current = null;
  };

  const stopAudio = () => {
    if (currentSourceRef.current) {
      try { currentSourceRef.current.stop(); } catch(e) {}
      currentSourceRef.current = null;
    }
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
      animationFrameRef.current = null;
    }
    setIsPlaying(false);
    setHighlightIndex(-1);
  };

  const playAudio = async () => {
    if (!currentPage?.audioData || isPlaying) return;

    stopAudio();

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }

    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') await ctx.resume();

    try {
      setIsPlaying(true);
      const data = decodeBase64(currentPage.audioData);
      const buffer = await decodeAudioData(data, ctx, 24000, 1);
      const duration = buffer.duration;

      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);

      source.onended = () => {
        setIsPlaying(false);
        setHighlightIndex(-1);
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      };

      startTimeRef.current = ctx.currentTime;
      source.start();
      currentSourceRef.current = source;

      // Logic to highlight words based on duration
      const updateHighlight = () => {
        const elapsed = ctx.currentTime - startTimeRef.current;
        const progress = elapsed / duration;

        // We add a small offset factor because real TTS usually has a slight delay or preamble
        // and words aren't perfectly uniform in length, but this is a solid approximation.
        const wordIndex = Math.floor(progress * words.length);

        if (wordIndex >= 0 && wordIndex < words.length) {
          setHighlightIndex(wordIndex);
        } else if (wordIndex >= words.length) {
          setHighlightIndex(-1);
        }

        if (isPlaying) {
          animationFrameRef.current = requestAnimationFrame(updateHighlight);
        }
      };

      animationFrameRef.current = requestAnimationFrame(updateHighlight);

    } catch (err) {
      console.error("Audio playback error", err);
      setIsPlaying(false);
      setHighlightIndex(-1);
    }
  };

  useEffect(() => {
    stopAudio();
  }, [currentIndex]);

  // Clean up on unmount
  useEffect(() => {
    return () => stopAudio();
  }, []);

  return (
    <div 
      className="w-full h-full flex flex-col items-center justify-start py-4 md:py-8"
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
    >
      <div className="w-full max-w-[550px] bg-white rounded-[2.5rem] shadow-[0_20px_50px_rgba(79,70,229,0.12)] overflow-hidden flex flex-col border border-indigo-50/50 relative">

        {/* Top Image Section */}
        <div className="w-full aspect-[4/3] bg-indigo-50 relative overflow-hidden group">
          {currentPage?.imageUrl ? (
            <img 
              key={currentPage.imageUrl}
              src={currentPage.imageUrl} 
              alt="Puslapio iliustracija" 
              className="w-full h-full object-cover animate-[fadeIn_0.5s_ease-out] transition-transform duration-700 group-hover:scale-105"
            />
          ) : (
            <div className="w-full h-full flex flex-col items-center justify-center gap-3 p-6 text-indigo-300">
              <div className="relative">
                <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-500 rounded-full animate-spin" />
                <div className="absolute inset-0 flex items-center justify-center text-xs">✨</div>
              </div>
              <p className="font-magic text-center text-sm animate-pulse">{t.painting}</p>
            </div>
          )}

          <div className="absolute top-4 right-4 bg-white/90 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-black text-indigo-600 shadow-sm border border-white/50">
            {currentIndex + 1} / {totalPages}
          </div>
        </div>

        {/* Content Section */}
        <div className="flex-1 p-6 sm:p-8 flex flex-col gap-5">
          <div className="space-y-4">
            <div className="min-h-[160px] sm:min-h-[200px] bg-indigo-50/20 p-4 rounded-3xl border border-indigo-50/30">
              <p className="text-lg sm:text-xl font-medium leading-relaxed text-indigo-950/80 transition-all">
                {words.map((word, idx) => (
                  <span 
                    key={idx}
                    className={`inline-block mr-1.5 transition-all duration-300 rounded-lg px-1 ${
                      idx === highlightIndex 
                        ? 'bg-yellow-200 text-indigo-950 scale-110 shadow-sm font-bold' 
                        : 'text-indigo-900/90'
                    }`}
                  >
                    {word}
                  </span>
                ))}
                {!currentPage?.text && "..."}
              </p>
            </div>
          </div>

          <div className="space-y-4">
            <button
              onClick={playAudio}
              disabled={!currentPage?.audioData || isPlaying}
              className={`w-full flex items-center justify-center gap-3 py-4 sm:py-5 rounded-[1.8rem] font-bold transition-all shadow-lg active:scale-95 ${
                isPlaying 
                  ? 'bg-indigo-50 text-indigo-400 border border-indigo-100' 
                  : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-100'
              }`}
            >
              {isPlaying ? (
                <>
                  <div className="flex gap-1.5 items-end h-4">
                    <div className="w-2 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0s]" />
                    <div className="w-2 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0.1s]" />
                    <div className="w-2 bg-indigo-400 rounded-full animate-[bounce_0.6s_infinite_0.2s]" />
                  </div>
                  <span className="text-sm sm:text-lg font-magic">{t.reading}</span>
                </>
              ) : (
                <>
                  <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M9.383 3.076A1 1 0 0110 4v12a1 1 0 01-1.707.707L4.586 13H2a1 1 0 01-1-1V8a1 1 0 011-1h2.586l3.707-3.707a1 1 0 011.09-.217zM14.657 2.929a1 1 0 011.414 0A9.972 9.972 0 0119 10a9.972 9.972 0 01-2.929 7.071 1 1 0 01-1.414-1.414A7.971 7.971 0 0017 10c0-2.21-.894-4.208-2.343-5.657a1 1 0 010-1.414zm-2.829 2.828a1 1 0 011.415 0A5.983 5.983 0 0115 10a5.983 5.983 0 01-1.757 4.243 1 1 0 01-1.415-1.415A3.984 3.984 0 0013 10a3.984 3.984 0 00-1.172-2.828a1 1 0 010-1.415z" clipRule="evenodd" />
                    </svg>
                  </div>
                  <span className="text-sm sm:text-lg font-magic tracking-wide">{t.readToMe}</span>
                </>
              )}
            </button>

            {isLastPage && (
              <button
                onClick={onReset}
                className="w-full flex items-center justify-center gap-2 py-4 rounded-[1.5rem] font-magic text-indigo-700 bg-indigo-50 hover:bg-indigo-100 transition-all border border-indigo-100 animate-[bounceIn_0.5s_ease-out]"
              >
                <span className="text-xl">✨</span>
                <span>{t.oneMore}</span>
                <span className="text-xl">✨</span>
              </button>
            )}
          </div>

          <div className="flex justify-between items-center px-2">
            <button 
              onClick={handlePrev} 
              disabled={currentIndex === 0}
              className={`flex items-center gap-1 text-[10px] font-black tracking-widest transition-all px-3 py-2 rounded-xl ${currentIndex === 0 ? 'opacity-0 pointer-events-none' : 'text-indigo-400 hover:text-indigo-600 hover:bg-indigo-50'}`}
            >
              <span>{t.previous}</span>
            </button>

            <div className="flex gap-2.5">
              {story.pages.map((_, i) => (
                <div 
                  key={i} 
                  className={`h-1.5 rounded-full transition-all duration-500 ${i === currentIndex ? 'bg-indigo-600 w-4 shadow-[0_0_8px_rgba(79,70,229,0.4)]' : 'bg-indigo-100 w-1.5'}`} 
                />
              ))}
            </div>

            <button 
              onClick={handleNext} 
              disabled={isLastPage}
              className={`flex items-center gap-1 text-[10px] font-black tracking-widest transition-all px-3 py-2 rounded-xl ${isLastPage ? 'opacity-0 pointer-events-none' : 'text-indigo-400 hover:text-indigo-600 hover:bg-indigo-50'}`}
            >
              <span>{t.next}</span>
            </button>
          </div>
        </div>
      </div>

      <p className="hidden md:block text-[10px] font-black text-indigo-300 uppercase tracking-[0.2em] mt-6 animate-pulse">
        {t.desktopHint}
      </p>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: scale(1.05); }
          to { opacity: 1; transform: scale(1); }
        }
        @keyframes bounceIn {
          0% { transform: scale(0.9); opacity: 0; }
          70% { transform: scale(1.05); }
          100% { transform: scale(1); opacity: 1; }
        }
      `}</style>
    </div>
  );
};

export default StoryReader;

import React, { useState, useEffect, useRef } from 'react';
import { translations } from '../translations';
import { Language } from '../types';

interface Props {
  onGenerate: (prompt: string, pageCount: number) => void;
  language: Language;
}

interface SuggestionItem {
  text: string;
  color: string;
  id: number;
}

const COLORS = [
  "bg-blue-50 text-blue-700 border-blue-100",
  "bg-green-50 text-green-700 border-green-100",
  "bg-yellow-50 text-yellow-700 border-yellow-100",
  "bg-pink-50 text-pink-700 border-pink-100",
  "bg-purple-50 text-purple-700 border-purple-100",
  "bg-orange-50 text-orange-700 border-orange-100",
  "bg-cyan-50 text-cyan-700 border-cyan-100"
];

const StoryWizard: React.FC<Props> = ({ onGenerate, language }) => {
  const [prompt, setPrompt] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const [pageCount, setPageCount] = useState(5);
  const [displayedSuggestions, setDisplayedSuggestions] = useState<SuggestionItem[]>([]);

  const t = translations[language];
  const pageOptions = [3, 5, 7, 10];

  // Initialize and randomize suggestions
  useEffect(() => {
    const shuffle = (array: string[]) => [...array].sort(() => Math.random() - 0.5);
    const shuffledPool = shuffle(t.suggestions);

    const initial = shuffledPool.slice(0, 4).map((text, i) => ({
      text,
      color: COLORS[i % COLORS.length],
      id: Math.random()
    }));

    setDisplayedSuggestions(initial);
    setPrompt(''); // Clear prompt on language change
  }, [language]);

  // Rotate suggestions overtime
  useEffect(() => {
    const interval = setInterval(() => {
      setDisplayedSuggestions(current => {
        // Find a random index to replace
        const indexToReplace = Math.floor(Math.random() * current.length);

        // Find all suggestions not currently shown
        const currentlyShownTexts = current.map(s => s.text);
        const availablePool = t.suggestions.filter(s => !currentlyShownTexts.includes(s));

        if (availablePool.length === 0) return current;

        const newSuggestionText = availablePool[Math.floor(Math.random() * availablePool.length)];
        const newColor = COLORS[Math.floor(Math.random() * COLORS.length)];

        const next = [...current];
        next[indexToReplace] = {
          text: newSuggestionText,
          color: newColor,
          id: Math.random()
        };
        return next;
      });
    }, 6000); // Swap one every 6 seconds

    return () => clearInterval(interval);
  }, [language, t.suggestions]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (prompt.trim()) {
      onGenerate(prompt, pageCount);
    }
  };

  return (
    <div className="w-full max-w-xl animate-[slideUp_0.5s_cubic-bezier(0.16,1,0.3,1)] py-2 sm:py-6">
      <div className="bg-white/90 backdrop-blur-xl rounded-[2rem] sm:rounded-[3rem] p-5 sm:p-12 shadow-[0_32px_64px_-16px_rgba(79,70,229,0.15)] border border-white relative overflow-hidden">
        <div className="absolute -top-24 -left-24 w-48 h-48 bg-indigo-200/10 blur-[60px] rounded-full pointer-events-none" />
        <div className="absolute -bottom-24 -right-24 w-48 h-48 bg-purple-200/10 blur-[60px] rounded-full pointer-events-none" />

        <div className="relative z-10">
          <h2 className="text-2xl md:text-4xl font-magic mb-1 md:mb-2 magic-color-title">
            {t.wizardTitle}
          </h2>
          <p className="text-indigo-400 font-bold mb-4 sm:mb-8 text-[10px] sm:text-base tracking-wide uppercase">
            {t.wizardSub}
          </p>

          <form onSubmit={handleSubmit} className="space-y-4 sm:space-y-8">
            <div className={`group relative transition-all duration-500 rounded-[1.5rem] sm:rounded-[2.5rem] p-1 ${
              isFocused ? 'bg-gradient-to-br from-indigo-400 to-purple-400 shadow-md scale-[1.01]' : 'bg-indigo-100/50 hover:bg-indigo-100'
            }`}>
              <div className="bg-white rounded-[1.3rem] sm:rounded-[2.3rem] overflow-hidden">
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  onFocus={() => setIsFocused(true)}
                  onBlur={() => setIsFocused(false)}
                  placeholder={t.placeholder}
                  className="w-full h-24 sm:h-40 bg-transparent p-4 sm:p-6 text-base sm:text-xl text-indigo-950 placeholder:text-indigo-200 focus:outline-none resize-none font-medium leading-relaxed"
                />
              </div>
            </div>

            <div className="flex flex-wrap gap-2 justify-center min-h-[80px] sm:min-h-[100px]">
              {displayedSuggestions.map((s) => (
                <button
                  key={s.id}
                  type="button"
                  onClick={() => setPrompt(s.text)}
                  className={`px-3 py-1.5 sm:px-4 sm:py-2 rounded-xl text-[10px] sm:text-[12px] font-bold transition-all hover:scale-105 active:scale-95 border border-transparent ${s.color} hover:shadow-sm animate-[popIn_0.4s_ease-out]`}
                >
                  {s.text}
                </button>
              ))}
            </div>

            <div className="space-y-2 sm:space-y-4">
              <label className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.2em] block">
                {t.storyLength}
              </label>
              <div className="bg-indigo-50/50 p-1.5 rounded-[1.5rem] sm:rounded-[2rem] flex justify-between gap-1 sm:gap-2 border border-indigo-100/50">
                {pageOptions.map((opt) => (
                  <button
                    key={opt}
                    type="button"
                    onClick={() => setPageCount(opt)}
                    className={`flex-1 py-2 sm:py-3 px-1 rounded-[1.2rem] sm:rounded-[1.5rem] text-[10px] sm:text-sm font-black transition-all duration-300 ${
                      pageCount === opt
                        ? 'bg-white text-indigo-700 border border-indigo-100 scale-105 ring-1 ring-indigo-50'
                        : 'text-indigo-300 hover:text-indigo-500 hover:bg-white/40'
                    }`}
                  >
                    {opt} <span className="text-[8px] sm:text-[10px] opacity-60">{t.pages}</span>
                  </button>
                ))}
              </div>
            </div>

            <button
              disabled={!prompt.trim()}
              className={`w-full relative group py-3.5 sm:py-5 rounded-[1.5rem] sm:rounded-[2.5rem] text-lg sm:text-xl font-magic transition-all overflow-hidden ${
                prompt.trim() 
                  ? 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-lg shadow-indigo-100' 
                  : 'bg-indigo-50 text-indigo-200 pointer-events-none'
              }`}
            >
              <span className="relative z-10 flex items-center justify-center gap-2 sm:gap-3">
                {prompt.trim() && <span className="animate-pulse">✨</span>}
                {t.createButton}
                {prompt.trim() && <span className="animate-pulse">✨</span>}
              </span>
              {prompt.trim() && (
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
              )}
            </button>
          </form>
        </div>
      </div>

      <style>{`
        @keyframes slideUp {
          from { opacity: 0; transform: translateY(20px) scale(0.98); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
        @keyframes popIn {
          0% { opacity: 0; transform: scale(0.8) translateY(10px); }
          100% { opacity: 1; transform: scale(1) translateY(0); }
        }
      `}</style>
    </div>
  );
};

