    touchStartX.current = e.touches[0].clientX;
  };
  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStartX.current) return;
    const diff = touchStartX.current - e.changedTouches[0].clientX;
    if (diff > 60) handleNext();
    else if (diff < -60) handlePrev();
    touchStartX.current = null;
  };

  const stopAudio = () => {
    isPlayingRef.current = false;
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.stop();
        currentSourceRef.current.onended = null;
      } catch (e) {}
      currentSourceRef.current = null;
    }
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
      animationFrameRef.current = null;
    }
    setIsPlaying(false);
    setHighlightIndex(-1);
    playedSfxRef.current.clear();
  };

  const playSfx = async (type: string) => {
    const url = SFX_MAP[type];
    if (!url) return;

    try {
      const audio = new Audio(url);
      audio.volume = 0.35; // Lower volume for SFX to avoid overpowering the narration
      audio.play();
    } catch (e) {
      console.warn("SFX failed to play", e);
